class Solution {
    public int[] popcountDepth(int[] nums, int[][] queries) {
        int n = nums.length;
        int[] depth = new int[n];
        for (int i = 0; i < n; i++) {
            int x = nums[i];
            int d = 0;
            while (x != 1) {
                x = Integer.bitCount(x);
                d++;
            }
            depth[i] = d;
        }
        int[] res = new int[queries.length];
        for (int i = 0; i < queries.length; i++) {
            if (queries[i][0] == 1) {
                int l = queries[i][1], r = queries[i][2], k = queries[i][3];
                int cnt = 0;
                for (int j = l; j <= r; j++) {
                    if (depth[j] == k) cnt++;
                }
                res[i] = cnt;
            } else {
                int idx = queries[i][1], val = queries[i][2];
                int x = val;
                int d = 0;
                while (x != 1) {
                    x = Integer.bitCount(x);
                    d++;
                }
                depth[idx] = d;
            }
        }
        return res;
    }
}
